export function visibleWidth(str: string): number {
	if (!str) return 0;
	// Replace tabs and strip Unicode format characters (Cf) that crash string-width
	const normalized = str.replace(/\t/g, "   ").replace(/\p{Cf}/gu, "");
	return stringWidth(normalized);
}

